// IEC-inspired SVG symbols — ported verbatim from sld_view.js / transmission_sld_view.js.
// Included into sld.rs.

/// Substation equipment symbol (30×30 viewBox), coloured by status.
fn equip_svg(category: &str, color: &str) -> String {
    match category {
        "switchgear" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><rect x="3" y="3" width="24" height="24" rx="2" fill="none" stroke="{c}" stroke-width="2"/><line x1="5" y1="5" x2="25" y2="25" stroke="{c}" stroke-width="2"/><line x1="25" y1="5" x2="5" y2="25" stroke="{c}" stroke-width="2"/></svg>"#, c = color),
        "transformer" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><circle cx="12" cy="15" r="8" fill="none" stroke="{c}" stroke-width="2"/><circle cx="18" cy="15" r="8" fill="none" stroke="{c}" stroke-width="2"/></svg>"#, c = color),
        "isolator" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><line x1="3" y1="15" x2="10" y2="15" stroke="{c}" stroke-width="2"/><line x1="10" y1="15" x2="20" y2="5" stroke="{c}" stroke-width="2"/><line x1="20" y1="15" x2="27" y2="15" stroke="{c}" stroke-width="2"/></svg>"#, c = color),
        "ct_vt" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><circle cx="15" cy="15" r="10" fill="none" stroke="{c}" stroke-width="2"/><circle cx="15" cy="15" r="2" fill="{c}"/></svg>"#, c = color),
        "surge_arrester" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><line x1="15" y1="2" x2="15" y2="7" stroke="{c}" stroke-width="2"/><polyline points="10,7 15,14 12,14 17,21 14,21 19,28" fill="none" stroke="{c}" stroke-width="2"/><line x1="8" y1="28" x2="22" y2="28" stroke="{c}" stroke-width="2"/></svg>"#, c = color),
        "protection" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><rect x="4" y="4" width="22" height="22" rx="2" fill="none" stroke="{c}" stroke-width="2"/><text x="15" y="20" text-anchor="middle" fill="{c}" font-size="14" font-weight="bold">R</text></svg>"#, c = color),
        "rmu" | "motorised_rmu" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><rect x="2" y="5" width="26" height="20" rx="2" fill="none" stroke="{c}" stroke-width="2"/><line x1="11" y1="5" x2="11" y2="25" stroke="{c}" stroke-width="1.5"/><line x1="19" y1="5" x2="19" y2="25" stroke="{c}" stroke-width="1.5"/></svg>"#, c = color),
        "battery" | "charger" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><line x1="8" y1="6" x2="22" y2="6" stroke="{c}" stroke-width="3"/><line x1="11" y1="11" x2="19" y2="11" stroke="{c}" stroke-width="1.5"/><line x1="8" y1="16" x2="22" y2="16" stroke="{c}" stroke-width="3"/><line x1="11" y1="21" x2="19" y2="21" stroke="{c}" stroke-width="1.5"/><line x1="15" y1="2" x2="15" y2="6" stroke="{c}" stroke-width="1.5"/><line x1="15" y1="21" x2="15" y2="28" stroke="{c}" stroke-width="1.5"/></svg>"#, c = color),
        "scada" | "rtu" | "control_panel" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><line x1="15" y1="2" x2="15" y2="8" stroke="{c}" stroke-width="2"/><line x1="10" y1="4" x2="15" y2="8" stroke="{c}" stroke-width="1.5"/><line x1="20" y1="4" x2="15" y2="8" stroke="{c}" stroke-width="1.5"/><rect x="5" y="10" width="20" height="16" rx="2" fill="none" stroke="{c}" stroke-width="2"/><rect x="8" y="13" width="14" height="8" rx="1" fill="none" stroke="{c}" stroke-width="1"/></svg>"#, c = color),
        "earthing" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><line x1="15" y1="2" x2="15" y2="12" stroke="{c}" stroke-width="2"/><line x1="5" y1="12" x2="25" y2="12" stroke="{c}" stroke-width="2"/><line x1="8" y1="18" x2="22" y2="18" stroke="{c}" stroke-width="2"/><line x1="11" y1="24" x2="19" y2="24" stroke="{c}" stroke-width="2"/></svg>"#, c = color),
        "cable" | "cable_bridge" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><circle cx="15" cy="15" r="10" fill="none" stroke="{c}" stroke-width="2"/><text x="15" y="19" text-anchor="middle" fill="{c}" font-size="10" font-weight="bold">C</text></svg>"#, c = color),
        "busbar" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><rect x="2" y="10" width="26" height="10" rx="2" fill="none" stroke="{c}" stroke-width="2"/><line x1="5" y1="15" x2="25" y2="15" stroke="{c}" stroke-width="2"/></svg>"#, c = color),
        "feeder_pillar" => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><rect x="6" y="2" width="18" height="26" rx="2" fill="none" stroke="{c}" stroke-width="2"/><text x="15" y="19" text-anchor="middle" fill="{c}" font-size="10" font-weight="bold">FP</text></svg>"#, c = color),
        _ => format!(r#"<svg viewBox="0 0 30 30" xmlns="http://www.w3.org/2000/svg"><circle cx="15" cy="15" r="10" fill="none" stroke="{c}" stroke-width="2"/><text x="15" y="19" text-anchor="middle" fill="{c}" font-size="10" font-weight="bold">?</text></svg>"#, c = color),
    }
}

/// Small equipment symbol (20×20) for transmission tower equipment chips.
fn equip_svg_small(category: &str, color: &str) -> String {
    match category {
        "switchgear" => format!(r#"<svg viewBox="0 0 20 20"><rect x="2" y="2" width="16" height="16" rx="1" fill="none" stroke="{c}" stroke-width="1.5"/><line x1="3" y1="3" x2="17" y2="17" stroke="{c}" stroke-width="1.5"/><line x1="17" y1="3" x2="3" y2="17" stroke="{c}" stroke-width="1.5"/></svg>"#, c = color),
        "transformer" => format!(r#"<svg viewBox="0 0 20 20"><circle cx="8" cy="10" r="5" fill="none" stroke="{c}" stroke-width="1.5"/><circle cx="12" cy="10" r="5" fill="none" stroke="{c}" stroke-width="1.5"/></svg>"#, c = color),
        "ct_vt" => format!(r#"<svg viewBox="0 0 20 20"><circle cx="10" cy="10" r="7" fill="none" stroke="{c}" stroke-width="1.5"/><circle cx="10" cy="10" r="1.5" fill="{c}"/></svg>"#, c = color),
        "surge_arrester" => format!(r#"<svg viewBox="0 0 20 20"><line x1="10" y1="2" x2="10" y2="5" stroke="{c}" stroke-width="1.5"/><polyline points="7,5 10,9 8,9 11,14 9,14 12,18" fill="none" stroke="{c}" stroke-width="1.5"/></svg>"#, c = color),
        "isolator" => format!(r#"<svg viewBox="0 0 20 20"><line x1="2" y1="10" x2="7" y2="10" stroke="{c}" stroke-width="1.5"/><line x1="7" y1="10" x2="13" y2="3" stroke="{c}" stroke-width="1.5"/><line x1="13" y1="10" x2="18" y2="10" stroke="{c}" stroke-width="1.5"/></svg>"#, c = color),
        _ => format!(r#"<svg viewBox="0 0 20 20"><circle cx="10" cy="10" r="7" fill="none" stroke="{c}" stroke-width="1.5"/><text x="10" y="13" text-anchor="middle" fill="{c}" font-size="8">?</text></svg>"#, c = color),
    }
}

/// Transmission tower symbol (60×100 viewBox), coloured by status.
fn tower_svg(tower_type: &str, color: &str) -> String {
    let c = color;
    match tower_type {
        "tubular_steel" => format!(r##"<svg viewBox="0 0 60 100" xmlns="http://www.w3.org/2000/svg"><circle cx="30" cy="2" r="2" fill="{c}"/><line x1="30" y1="4" x2="30" y2="10" stroke="{c}" stroke-width="1.5"/><line x1="8" y1="12" x2="52" y2="12" stroke="{c}" stroke-width="2"/><line x1="10" y1="12" x2="10" y2="20" stroke="#666" stroke-width="1"/><circle cx="10" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="50" y1="12" x2="50" y2="20" stroke="#666" stroke-width="1"/><circle cx="50" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="12" y1="30" x2="48" y2="30" stroke="{c}" stroke-width="2"/><line x1="14" y1="30" x2="14" y2="38" stroke="#666" stroke-width="1"/><circle cx="14" cy="39" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="46" y1="30" x2="46" y2="38" stroke="#666" stroke-width="1"/><circle cx="46" cy="39" r="2" fill="none" stroke="{c}" stroke-width="1"/><rect x="24" y="12" width="12" height="76" rx="4" fill="none" stroke="{c}" stroke-width="2"/><ellipse cx="30" cy="92" rx="14" ry="4" fill="none" stroke="{c}" stroke-width="1.5"/><rect x="16" y="94" width="28" height="4" rx="1" fill="{c}" opacity="0.2"/></svg>"##, c = c),
        "wood_pole" => format!(r##"<svg viewBox="0 0 60 100" xmlns="http://www.w3.org/2000/svg"><circle cx="30" cy="2" r="2" fill="{c}"/><line x1="30" y1="4" x2="30" y2="10" stroke="{c}" stroke-width="1.5"/><line x1="8" y1="12" x2="52" y2="12" stroke="{c}" stroke-width="2.5"/><line x1="10" y1="12" x2="10" y2="20" stroke="#666" stroke-width="1"/><circle cx="10" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="50" y1="12" x2="50" y2="20" stroke="#666" stroke-width="1"/><circle cx="50" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="30" y1="12" x2="30" y2="92" stroke="#8B6914" stroke-width="6" stroke-linecap="round"/><rect x="20" y="92" width="20" height="6" rx="1" fill="{c}" opacity="0.2"/></svg>"##, c = c),
        "concrete_pole" => format!(r##"<svg viewBox="0 0 60 100" xmlns="http://www.w3.org/2000/svg"><circle cx="30" cy="2" r="2" fill="{c}"/><line x1="30" y1="4" x2="30" y2="10" stroke="{c}" stroke-width="1.5"/><line x1="8" y1="12" x2="52" y2="12" stroke="{c}" stroke-width="2"/><line x1="10" y1="12" x2="10" y2="20" stroke="#666" stroke-width="1"/><circle cx="10" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="50" y1="12" x2="50" y2="20" stroke="#666" stroke-width="1"/><circle cx="50" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="12" y1="30" x2="48" y2="30" stroke="{c}" stroke-width="2"/><line x1="14" y1="30" x2="14" y2="38" stroke="#666" stroke-width="1"/><circle cx="14" cy="39" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="46" y1="30" x2="46" y2="38" stroke="#666" stroke-width="1"/><circle cx="46" cy="39" r="2" fill="none" stroke="{c}" stroke-width="1"/><path d="M25,12 L23,90 L37,90 L35,12 Z" fill="none" stroke="{c}" stroke-width="1.5"/><line x1="24" y1="30" x2="36" y2="30" stroke="{c}" stroke-width="0.5" opacity="0.4"/><line x1="24" y1="45" x2="36" y2="45" stroke="{c}" stroke-width="0.5" opacity="0.4"/><line x1="23" y1="60" x2="37" y2="60" stroke="{c}" stroke-width="0.5" opacity="0.4"/><line x1="23" y1="75" x2="37" y2="75" stroke="{c}" stroke-width="0.5" opacity="0.4"/><rect x="18" y="90" width="24" height="6" rx="1" fill="{c}" opacity="0.2"/></svg>"##, c = c),
        "monopole" => format!(r##"<svg viewBox="0 0 60 100" xmlns="http://www.w3.org/2000/svg"><circle cx="30" cy="2" r="2" fill="{c}"/><line x1="30" y1="4" x2="30" y2="10" stroke="{c}" stroke-width="1.5"/><line x1="8" y1="12" x2="52" y2="12" stroke="{c}" stroke-width="2"/><line x1="10" y1="12" x2="10" y2="20" stroke="#666" stroke-width="1"/><circle cx="10" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="50" y1="12" x2="50" y2="20" stroke="#666" stroke-width="1"/><circle cx="50" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="12" y1="30" x2="48" y2="30" stroke="{c}" stroke-width="2"/><line x1="14" y1="30" x2="14" y2="38" stroke="#666" stroke-width="1"/><circle cx="14" cy="39" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="46" y1="30" x2="46" y2="38" stroke="#666" stroke-width="1"/><circle cx="46" cy="39" r="2" fill="none" stroke="{c}" stroke-width="1"/><path d="M27,10 L25,88 L35,88 L33,10 Z" fill="none" stroke="{c}" stroke-width="1.5"/><ellipse cx="30" cy="90" rx="14" ry="5" fill="none" stroke="{c}" stroke-width="1.5"/><rect x="16" y="93" width="28" height="5" rx="1" fill="{c}" opacity="0.2"/></svg>"##, c = c),
        "h_frame" => format!(r##"<svg viewBox="0 0 60 100" xmlns="http://www.w3.org/2000/svg"><circle cx="30" cy="2" r="2" fill="{c}"/><line x1="30" y1="4" x2="30" y2="8" stroke="{c}" stroke-width="1.5"/><line x1="12" y1="8" x2="48" y2="8" stroke="{c}" stroke-width="2.5"/><line x1="4" y1="12" x2="56" y2="12" stroke="{c}" stroke-width="2"/><line x1="8" y1="12" x2="8" y2="20" stroke="#666" stroke-width="1"/><circle cx="8" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="30" y1="12" x2="30" y2="20" stroke="#666" stroke-width="1"/><circle cx="30" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="52" y1="12" x2="52" y2="20" stroke="#666" stroke-width="1"/><circle cx="52" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="16" y1="8" x2="16" y2="90" stroke="{c}" stroke-width="3"/><line x1="44" y1="8" x2="44" y2="90" stroke="{c}" stroke-width="3"/><line x1="16" y1="50" x2="44" y2="50" stroke="{c}" stroke-width="1.5"/><rect x="8" y="90" width="18" height="6" rx="1" fill="{c}" opacity="0.2"/><rect x="34" y="90" width="18" height="6" rx="1" fill="{c}" opacity="0.2"/></svg>"##, c = c),
        // lattice_steel (default)
        _ => format!(r##"<svg viewBox="0 0 60 100" xmlns="http://www.w3.org/2000/svg"><circle cx="30" cy="2" r="2" fill="{c}"/><line x1="30" y1="4" x2="30" y2="10" stroke="{c}" stroke-width="1.5"/><line x1="8" y1="12" x2="52" y2="12" stroke="{c}" stroke-width="2"/><line x1="10" y1="12" x2="10" y2="20" stroke="#666" stroke-width="1"/><circle cx="10" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="50" y1="12" x2="50" y2="20" stroke="#666" stroke-width="1"/><circle cx="50" cy="21" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="12" y1="30" x2="48" y2="30" stroke="{c}" stroke-width="2"/><line x1="14" y1="30" x2="14" y2="38" stroke="#666" stroke-width="1"/><circle cx="14" cy="39" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="46" y1="30" x2="46" y2="38" stroke="#666" stroke-width="1"/><circle cx="46" cy="39" r="2" fill="none" stroke="{c}" stroke-width="1"/><line x1="22" y1="12" x2="10" y2="82" stroke="{c}" stroke-width="2"/><line x1="38" y1="12" x2="50" y2="82" stroke="{c}" stroke-width="2"/><line x1="18" y1="35" x2="42" y2="55" stroke="{c}" stroke-width="1"/><line x1="42" y1="35" x2="18" y2="55" stroke="{c}" stroke-width="1"/><line x1="15" y1="55" x2="45" y2="75" stroke="{c}" stroke-width="1"/><line x1="45" y1="55" x2="15" y2="75" stroke="{c}" stroke-width="1"/><line x1="18" y1="45" x2="42" y2="45" stroke="{c}" stroke-width="1"/><line x1="14" y1="65" x2="46" y2="65" stroke="{c}" stroke-width="1"/><line x1="10" y1="82" x2="4" y2="92" stroke="{c}" stroke-width="2"/><line x1="50" y1="82" x2="56" y2="92" stroke="{c}" stroke-width="2"/><rect x="0" y="92" width="12" height="6" rx="1" fill="{c}" opacity="0.2"/><rect x="48" y="92" width="12" height="6" rx="1" fill="{c}" opacity="0.2"/></svg>"##, c = c),
    }
}
